import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as l,c as t,f as o}from"./app-74137bf2.js";const i={},c=o('<h3 id="场景" tabindex="-1"><a class="header-anchor" href="#场景" aria-hidden="true">#</a> 场景</h3><ol><li>系统一些场景的多选选择器，内容过长过多一般有上千条数据，并且选择多个后也不好显示以及删除单个，所以需要一个多选列表组件。</li><li>它有搜索框、可以单选与多选，单选是上下布局，多选显示左右布局。</li></ol><h3 id="解决方案" tabindex="-1"><a class="header-anchor" href="#解决方案" aria-hidden="true">#</a> 解决方案</h3><ol><li>使用插件<code>vue-virtual-scroller</code>,它是长列表优化方案之一。</li><li>原理是：它只会把展示给用户的那部分 dom 渲染出来，比如滚到上面的 dom 就会回收掉</li></ol><h3 id="实现" tabindex="-1"><a class="header-anchor" href="#实现" aria-hidden="true">#</a> 实现</h3><ol><li>根据传进来的参数<code>multiple（true\\false）</code>决定页面的布局，如果单选则显示为上下布局；多选则为左右布局，右边显示选中的值。 <ul><li>页面的布局根据<code>flex</code>的<code>flex-direction</code>显示。 <ul><li><code>style=&quot;display:flex;overflow: auto;&quot; :style=&quot;{&#39;flex-direction&#39;:mydirection}&quot;</code></li></ul></li></ul></li><li>数据列表使用插件<code>vue-virtual-scroller</code>的<code>RecycleScroller组件</code>展示 <ul><li><code>RecycleScroller</code>组件是做固定高度场景，需指定<code>items itemsize keyfield</code>, keyfieled需唯一稳定 <ul><li>代码：<code>&lt;RecycleScroller style=&quot;height: 100%;&quot; :items=&quot;renderList&quot; :item-size=&quot;32&quot; key-field=&quot;name&quot; v-slot=&quot;{ item }&quot;&gt;</code></li></ul></li><li>多选模式：主要是每个item都有_checked选项，点击设置<code>item._checked = !item._checked；</code></li><li>搜索关键字：为了用户体验过滤后的列表数据项中的关键字为黄色。 <ul><li>每个数据项会循环匹配是否有keyword，根据replace方法把值替换上带strong标签与样式的关键值。<code>item.text.replace(new RegExp(_firstword, &quot;gm&quot;), &lt;strong class=&quot;searchText&quot;&gt;${_firstword}&lt;/strong&gt;)</code></li></ul></li></ul></li><li>列表自定义选项渲染：比如左边数据列表需要禁选效果，点击可以提示原因,使用作用域插槽实现 <ul><li>列表自定义选项渲染，item值使用插槽占位，方便业务组件传递数据项内容，比如数据列表需要禁选效果，并且点击可以提示原因。</li></ul></li><li>业务系统使用组件：<code>&lt;fx-listselect style=&quot;height: 100%;flex: 1;&quot; layout=&quot;row&quot; :listdata=&quot;options&quot; v-model=&quot;lstCheck&quot;&gt;&lt;/fx-listselect&gt;</code></li></ol>',6),d=[c];function r(u,s){return l(),t("div",null,d)}const n=e(i,[["render",r],["__file","组件库之组件实例.html.vue"]]);export{n as default};
